import { call, put, takeEvery } from 'redux-saga/effects';
import { ResponseApi } from '../../store/types';
import { logger } from '../../../utils';
import {
  GET_NOTIFICATION_ASYNC,
  GET_NOTIFICATION_FAILURE,
  GET_NOTIFICATION_PROCESSING,
  GET_NOTIFICATION_SUCCESS,
  LOAD_MORE_NOTIFICATION_ASYNC,
  LOAD_MORE_NOTIFICATION_SUCCESS,
  LOAD_MORE_NOTIFICATION_LOADING,
  MARK_ALL_READ_PROCESSING,
  MARK_ALL_READ_FAILURE,
  MARK_ALL_READ_SUCCESS,
  MARK_ALL_READ_ASYNC,
  MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING,
  MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE,
  MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS,
  MARK_AS_READ_NOTIFICATION_BY_ID_ASYNC,
  GET_NOTIFICATIONS_UNREAD_ASYNC,
  GET_NOTIFICATIONS_UNREAD_SUCCESS,
  GET_NOTIFICATIONS_UNREAD_FAILURE,
  GET_NOTIFICATIONS_UNREAD_PROCESSING,
} from './contants';
import {
  getNotifications,
  markAllAsRead,
  markAsReadNotificationById,
  getNotificationsUnread,
} from '../../../api/notification';

const getNotification = function* (action: {
  type: string;
  payload: {
    page: number;
    pageSize: number;
    category: number;
    categoryName: string;
  };
}): Generator<any, void, any> {
  try {
    yield put({
      type: GET_NOTIFICATION_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoading: true,
      },
    });

    const response = (yield call(getNotifications, {
      PageIndex: action.payload.page || 1,
      PageSize: action.payload.pageSize || 20,
      Category: action.payload.category,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_NOTIFICATION_FAILURE,
        payload: {
          categoryName: action.payload.categoryName,
          error: response.message,
        },
      });
      return;
    }

    yield put({
      type: GET_NOTIFICATION_SUCCESS,
      payload: {
        categoryName: action.payload.categoryName,
        data: response.data,
      },
    });
  } catch (error) {
    logger('error getNotification', error);
  } finally {
    yield put({
      type: GET_NOTIFICATION_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoading: false,
      },
    });
  }
};

const loadMoreNotification = function* (action: {
  type: string;
  payload: {
    page: number;
    pageSize: number;
    category: number;
    categoryName: string;
  };
}): Generator<any, void, any> {
  try {
    yield put({
      type: LOAD_MORE_NOTIFICATION_LOADING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoadingMore: true,
      },
    });

    const response = (yield call(getNotifications, {
      PageIndex: action.payload.page,
      PageSize: action.payload.pageSize || 20,
      Category: action.payload.category,
    })) as ResponseApi;

    if (response.status !== 200) {
      logger('error loadMoreNotification', response.message);
      return;
    }

    yield put({
      type: LOAD_MORE_NOTIFICATION_SUCCESS,
      payload: {
        categoryName: action.payload.categoryName,
        data: response.data,
        page: action.payload.page,
      },
    });
  } catch (error) {
    logger('error loadMoreNotification', error);
  } finally {
    yield put({
      type: LOAD_MORE_NOTIFICATION_LOADING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoadingMore: false,
      },
    });
  }
};

export const markAllAsReadAsync = function* (action: {
  type: string;
  payload: {
    category: number;
    categoryName: string;
  };
}): Generator<any, void, any> {
  try {
    yield put({
      type: MARK_ALL_READ_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoading: true,
      },
    });

    const response = (yield call(markAllAsRead, {
      Category: action.payload.category,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: MARK_ALL_READ_FAILURE,
        payload: {
          categoryName: action.payload.categoryName,
          error: response.message,
        },
      });
      return;
    }

    yield put({
      type: MARK_ALL_READ_SUCCESS,
      payload: {
        categoryName: action.payload.categoryName,
        data: response.data,
      },
    });
  } catch (error) {
    logger('error markAllAsRead', error);
  } finally {
    yield put({
      type: MARK_ALL_READ_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        isLoading: false,
      },
    });
  }
};

const markAsReadNotificationByIdAsync = function* (action: {
  type: string;
  payload: {
    id: string;
    categoryName: string;
  };
}): Generator<any, void, any> {
  try {
    yield put({
      type: MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        id: action.payload.id,
      },
    });

    const response = (yield call(markAsReadNotificationById, {
      id: action.payload.id,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE,
        payload: {
          categoryName: action.payload.categoryName,
          error: response.message,
        },
      });
      return;
    }

    yield put({
      type: MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS,
      payload: {
        id: action.payload.id,
        categoryName: action.payload.categoryName,
        data: response.data,
      },
    });
  } catch (error) {
    logger('error markAsReadNotificationById', error);
  } finally {
    yield put({
      type: MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING,
      payload: {
        categoryName: action.payload.categoryName,
        id: null,
      },
    });
  }
};

const getNotificationsUnreadSaga = function* (): Generator<any, void, any> {
  try {
    yield put({
      type: GET_NOTIFICATIONS_UNREAD_PROCESSING,
      payload: true,
    });
    const response = (yield call(getNotificationsUnread)) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_NOTIFICATIONS_UNREAD_FAILURE,
        payload: response.message,
      });
      return;
    }

    yield put({
      type: GET_NOTIFICATIONS_UNREAD_SUCCESS,
      payload: response.data,
    });
  } catch (error) {
    logger('error getNotificationsUnread', error);
  } finally {
    yield put({
      type: GET_NOTIFICATIONS_UNREAD_PROCESSING,
      payload: false,
    });
  }
};

export default function* notificationSaga() {
  yield takeEvery(GET_NOTIFICATION_ASYNC, getNotification);
  yield takeEvery(LOAD_MORE_NOTIFICATION_ASYNC, loadMoreNotification);
  yield takeEvery(MARK_ALL_READ_ASYNC, markAllAsReadAsync);
  yield takeEvery(
    MARK_AS_READ_NOTIFICATION_BY_ID_ASYNC,
    markAsReadNotificationByIdAsync,
  );
  yield takeEvery(GET_NOTIFICATIONS_UNREAD_ASYNC, getNotificationsUnreadSaga);
}
