import {
  GET_FRIEND_REFERRAL_DETAIL_CLEAR,
  GET_FRIEND_REFERRAL_DETAIL_FAILED,
  GET_FRIEND_REFERRAL_DETAIL_PROGRESS,
  GET_FRIEND_REFERRAL_DETAIL_SUCCESS,
  GET_FRIEND_REFERRAL_PROGRESS,
  GET_FRIEND_REFERRAL_SUCCESS,
} from './contants';
import { ReferFriendAction } from './actions';
import { ReferFriendState } from './types';

export const initialState: ReferFriendState = {
  data: {
    referralInfo: {
      referralCode: '',
      referralLink: '',
      referralLinkApple: '',
    },
    referralData: [],
  },
  loading: false,
  referralDetail: {
    isLoading: false,
    data: null,
    error: null,
  },
};

export default function referFriendReducer(
  state = initialState,
  action: ReferFriendAction,
): ReferFriendState {
  switch (action.type) {
    case GET_FRIEND_REFERRAL_SUCCESS:
      return {
        ...state,
        data: {
          referralInfo: action.payload.referralInfo,
          referralData: action.payload.referralData,
        },
      };
    case GET_FRIEND_REFERRAL_PROGRESS:
      return {
        ...state,
        loading: action.payload,
      };
    case GET_FRIEND_REFERRAL_DETAIL_SUCCESS:
      return {
        ...state,
        referralDetail: {
          isLoading: false,
          data: action.payload,
          error: null,
        },
      };
    case GET_FRIEND_REFERRAL_DETAIL_PROGRESS:
      return {
        ...state,
        referralDetail: {
          ...state.referralDetail,
          isLoading: action.payload,
        },
      };
    case GET_FRIEND_REFERRAL_DETAIL_FAILED:
      return {
        ...state,
        referralDetail: {
          ...state.referralDetail,
          isLoading: false,
          error: action.payload,
        },
      };
    case GET_FRIEND_REFERRAL_DETAIL_CLEAR:
      return {
        ...state,
        referralDetail: {
          isLoading: false,
          data: null,
          error: null,
        },
      };
    default:
      return state;
  }
}
