/**
 * Generic async state wrapper for consistent loading/error handling
 */
export interface AsyncState<T> {
  data: T;
  isLoading: boolean;
  error: string | null;
}

/**
 * JobDetail state with nested async states for better organization
 */
export interface JobDetailState {
  workOrder: AsyncState<JobDetailType | null>;
  materialList: AsyncState<MaterialItem[] | null>;
  chatGroup: AsyncState<ChatGroup | null>;
  // Checklists keyed by screen to prevent overwrite between screens
  checklists: {
    [key: string]: AsyncState<ChecklistItem[]>;
  };
  saveWorkOrder: AsyncState<null>;
  // JobReady checklist state - reuses checklists for items
  jobReadyData: AsyncState<JobReadyData | null>;
  submitJobReady: AsyncState<boolean>;
  saveJobReadyItem: AsyncState<boolean>;
  // Job Start checklist state
  jobStartData: AsyncState<JobStartChecklistData | null>;
  submitJobStart: AsyncState<boolean>;
  // Work Order Participants
  participants: AsyncState<CrewParticipant[]>;
  // Work Order Detail for Participants (leader viewing member's job)
  participantWorkOrder: AsyncState<JobDetailType | null>;
  // Material Delivered (read-only work order detail + delivery chat)
  materialDelivered: AsyncState<JobDetailType | null>;
  materialDeliveredChat: AsyncState<WorkOrderChat | null>;
  // Verify Material VPO
  vpoData: AsyncState<VPOChecklistItem[] | null>;
  submitVpo: AsyncState<boolean>;
  // Material Left
  materialLeftData: AsyncState<any[] | null> & { isSubmitted: boolean };
  submitMaterialLeft: AsyncState<boolean>;
}

