import client from './configAxios';
import {
  getNotifications as getNotificationsEndpoint,
  markAllAsRead as markAllAsReadEndpoint,
  markReadNotification,
  getNotificationsUnread as getNotificationsUnreadEndpoint,
} from './endpoint';
import { logger } from '../utils';

export const getNotifications = async ({
  Category = 1,
  PageIndex = 0,
  PageSize = 20,
}: {
  Category?: number;
  PageIndex?: number;
  PageSize?: number;
}) => {
  try {
    const response = await client.get(
      `${getNotificationsEndpoint}?Category=${Category}&PageIndex=${PageIndex}&PageSize=${PageSize}`,
    );
    return {
      status: response.status,
      code: response.status,
      data: response.data?.data,
    };
  } catch (error: any) {
    logger('error getNotifications', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

