import { call, put, takeEvery } from 'redux-saga/effects';
import {
  createRoomChat,
  getMessagesByRoomId,
  getMyRooms,
  getUnreadMessage,
} from '../../../api/message';
import {
  CREATE_ROOM_CHAT_BY_NETWORK_ASYNC,
  CREATE_ROOM_CHAT_BY_NETWORK_FAILED,
  CREATE_ROOM_CHAT_BY_NETWORK_PROGRESS,
  CREATE_ROOM_CHAT_BY_NETWORK_SUCCESS,
  GET_MESSAGES_BY_ROOM_ID_ASYNC,
  GET_MESSAGES_BY_ROOM_ID_FAILED,
  GET_MESSAGES_BY_ROOM_ID_PROGRESS,
  GET_MESSAGES_BY_ROOM_ID_SUCCESS,
  GET_MY_ROOMS_ASYNC,
  GET_MY_ROOMS_FAILED,
  GET_MY_ROOMS_PROGRESS,
  GET_MY_ROOMS_SUCCESS,
  GET_UNREAD_MESSAGE_ASYNC,
  GET_UNREAD_MESSAGE_FAILED,
  GET_UNREAD_MESSAGE_PROGRESS,
  GET_UNREAD_MESSAGE_SUCCESS,
} from './constants';
import { ResponseApi } from '../../store/types';
import {
  HIDE_LOADING_OVERLAY,
  SHOW_ALERT,
  SHOW_LOADING_OVERLAY,
} from '../app/constants';
import i18n from '../../../i18n';
import { AppAlertModalProps } from '../app/types';
import { store } from '../../store';
import { fetchNetwork } from '../../../api/network';
import { GET_NETWORK_SUCCESS } from '../network/contants';

function* getMyRoomsSaga(): Generator<any, void, any> {
  try {
    yield put({ type: GET_MY_ROOMS_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(getMyRooms)) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_MY_ROOMS_FAILED, payload: response.message });
      return;
    }
    yield put({ type: GET_MY_ROOMS_SUCCESS, payload: response.data });
  } catch (error) {
    yield put({ type: GET_MY_ROOMS_FAILED, payload: error });
  } finally {
    yield put({ type: GET_MY_ROOMS_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
}

function* getMessagesByRoomIdSaga(action: any): Generator<any, void, any> {
  try {
    yield put({ type: GET_MESSAGES_BY_ROOM_ID_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(
      getMessagesByRoomId,
      action.payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_MESSAGES_BY_ROOM_ID_FAILED,
        payload: response.message,
      });
      return;
    }
    yield put({
      type: GET_MESSAGES_BY_ROOM_ID_SUCCESS,
      payload: response.data,
    });
  } catch (error) {
    yield put({ type: GET_MESSAGES_BY_ROOM_ID_FAILED, payload: error });
  } finally {
    yield put({ type: GET_MESSAGES_BY_ROOM_ID_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
}

function* getUnreadMessageSaga(): Generator<any, void, any> {
  try {
    yield put({ type: GET_UNREAD_MESSAGE_PROGRESS, payload: true });
    const response = (yield call(getUnreadMessage)) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_UNREAD_MESSAGE_FAILED, payload: response.message });
      return;
    }
    yield put({ type: GET_UNREAD_MESSAGE_SUCCESS, payload: response.data });
  } catch (error) {
    yield put({ type: GET_UNREAD_MESSAGE_FAILED, payload: error });
  } finally {
    yield put({ type: GET_UNREAD_MESSAGE_PROGRESS, payload: false });
  }
}

function* createRoomChatByNetworkSaga(action: any): Generator<any, void, any> {
  try {
    yield put({ type: CREATE_ROOM_CHAT_BY_NETWORK_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(createRoomChat, {
      chatName: '',
      isGroup: false,
      memberIds: action.payload.memberIds,
      roomType: action.payload.roomType,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: CREATE_ROOM_CHAT_BY_NETWORK_FAILED,
        payload: response.message,
      });
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: response.message,
          type: 'error',
          buttonText: i18n.t('OK'),
        } as AppAlertModalProps,
      });
      return;
    }
    const roomChat = (yield call(getMyRooms)) as ResponseApi;
    if (roomChat.status !== 200) {
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: roomChat.message,
          type: 'error',
          buttonText: i18n.t('OK'),
        } as AppAlertModalProps,
      });
      return;
    }

    const newlyCreatedRoom = roomChat.data.find(
      (room: any) => room.id === response.data.id,
    );
    if (!newlyCreatedRoom) {
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: i18n.t('NEWLY_CREATED_ROOM_NOT_FOUND'),
        } as AppAlertModalProps,
      });
      return;
    }

    const user = store.getState().auth.userProfile;
    const token = store.getState().auth.token;

    const payload = {
      chatId: newlyCreatedRoom?.id,
      userId: user?.accountId,
      token,
      chatName: newlyCreatedRoom?.chatName
        ? newlyCreatedRoom?.chatName
        : action?.payload?.chatName,
      memberInfo: newlyCreatedRoom?.memberInfo,
      isGroup: newlyCreatedRoom?.isGroup,
    };

    const storeNetwork = store.getState().network.network;

    const page = storeNetwork?.data?.pageIndex ?? 1;
    const pageSize = storeNetwork?.data?.pageSize ?? 20;

    const listUserNetwork = yield call(fetchNetwork, {
      keyword: action?.payload?.searchText,
      page: 1,
      pageSize: pageSize * page,
    });

    if (listUserNetwork.status === 200) {
      const newNetwork = {
        ...storeNetwork.data,
        items: listUserNetwork.data.items,
      };
      yield put({
        type: GET_NETWORK_SUCCESS,
        payload: newNetwork,
      });
    }

    yield call(action.payload.onNavigate, payload);
    yield put({
      type: CREATE_ROOM_CHAT_BY_NETWORK_SUCCESS,
      payload: response.data,
    });
  } catch (error) {
    yield put({ type: CREATE_ROOM_CHAT_BY_NETWORK_FAILED, payload: error });
  } finally {
    yield put({ type: CREATE_ROOM_CHAT_BY_NETWORK_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
}

export default function* messageSaga() {
  yield takeEvery(GET_MY_ROOMS_ASYNC, getMyRoomsSaga);
  yield takeEvery(GET_MESSAGES_BY_ROOM_ID_ASYNC, getMessagesByRoomIdSaga);
  yield takeEvery(GET_UNREAD_MESSAGE_ASYNC, getUnreadMessageSaga);
  yield takeEvery(
    CREATE_ROOM_CHAT_BY_NETWORK_ASYNC,
    createRoomChatByNetworkSaga,
  );
}
